__attribute__((reqd_opencl_version(120)))

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__kernel void dynproc_kernel(
    int pyramid_height,
    __global const int* wall,
    __global const int* src_result,
    __global int* dst_result,
    int cols,
    int rows,
    int t,
    int borderCols,
    int halo,
    __local int* local_src,
    __local int* local_dst,
    __global int* outputBuffer)
{
    int col = get_global_id(0);
    int local_idx = get_local_id(0);

    if (col >= cols) {
        return;
    }

    // Load initial src values into local memory
    local_src[local_idx] = src_result[col];

    // Process pyramid_height rows
    for (int h = 0; h < pyramid_height; h++) {
        int current_row = t + h;
        if (current_row >= rows - 1) {
            break;
        }

        // Compute min from three neighbors
        int min_val = local_src[local_idx];

        if (col > 0) {
            int left_val = local_src[local_idx - 1];
            min_val = MIN(min_val, left_val);
        }

        if (col < cols - 1) {
            int right_val = local_src[local_idx + 1];
            min_val = MIN(min_val, right_val);
        }

        // Get wall value for current row and column
        int wall_index = (current_row + 1) * cols + col;
        int wall_val = wall[wall_index - cols];  // wall buffer starts from row 1

        // Store result
        local_dst[local_idx] = wall_val + min_val;

        // Update src for next iteration
        local_src[local_idx] = local_dst[local_idx];
    }

    // Write final result to global memory
    dst_result[col] = local_src[local_idx];
}
